"use client";

import { useParams, useRouter } from "next/navigation";
import { useState } from "react";
import Link from "next/link"; 

interface Loja {
  id: number;
  nome: string;
  imagem: string;
  status: "Aberto" | "Fechado";
}

export default function PaginaLojas() {
  const params = useParams(); 
  const router = useRouter();
  
  // Tratamento dos parâmetros da URL
  const city = params?.city ? decodeURIComponent(String(params.city)) : '';
  const category = params?.category ? decodeURIComponent(String(params.category)) : '';

  // DADOS DE EXEMPLO (MOCK) - Depois ligamos isto à base de dados real
  const [lojas] = useState<Loja[]>([
    { id: 1, nome: "Restaurante O Galo", imagem: "galo.png", status: "Aberto" },
    { id: 2, nome: "Pizzaria Barcelos", imagem: "pizza.png", status: "Fechado" },
    { id: 3, nome: "Hamburgueria Central", imagem: "burger.png", status: "Aberto" },
    { id: 4, nome: "Sushi Bar", imagem: "sushi.png", status: "Aberto" },
  ]);

  return (
    <main style={{ minHeight: '100vh', position: 'relative', backgroundColor: '#f9f9f9', paddingBottom: '50px' }}>
       
      {/* Topo (Logo) */}
      <Link href="/">
        <img id="logoini" src="/assets/img/logo.png" alt="Logo" style={{ position: 'absolute', top: '20px', left: '20px', width: '150px', zIndex: 20, cursor: 'pointer' }} />
      </Link>
      
      {/* Onda Topo */}
      <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '150px', background: 'white', borderBottomLeftRadius: '50% 20%', borderBottomRightRadius: '50% 20%', zIndex: 10, boxShadow: '0 4px 6px rgba(0,0,0,0.05)' }}></div>

      <div className="container" style={{ paddingTop: '180px', position: 'relative', zIndex: 20, paddingLeft: '20px', paddingRight: '20px' }}>
        
        {/* Título Dinâmico */}
        <h1 style={{ 
            color: '#dc3545', 
            textAlign: 'center', 
            textTransform: 'uppercase', 
            fontWeight: '800', 
            fontSize: '2.5rem',
            marginBottom: '40px',
            textShadow: '2px 2px 0px rgba(0,0,0,0.1)'
        }}>
          {category.replace('-', ' ')} <span style={{ color: '#333', fontSize: '1.5rem', display: 'block', marginTop: '10px' }}>em {city}</span>
        </h1>

        {/* LISTA DE LOJAS */}
        <div className="row justify-content-center">
          {lojas.map((loja) => (
            <div key={loja.id} className="col-12 col-md-6 col-lg-4" style={{ marginBottom: '25px' }}>
              
              <div style={{ 
                background: 'white', 
                borderRadius: '20px', 
                padding: '20px', 
                display: 'flex', 
                alignItems: 'center',
                boxShadow: '0 10px 25px rgba(0,0,0,0.05)',
                cursor: 'pointer',
                transition: 'transform 0.2s ease, box-shadow 0.2s ease',
                border: '1px solid #eee'
              }}
              onMouseEnter={(e) => {
                  e.currentTarget.style.transform = 'translateY(-5px)';
                  e.currentTarget.style.boxShadow = '0 15px 30px rgba(0,0,0,0.1)';
              }}
              onMouseLeave={(e) => {
                  e.currentTarget.style.transform = 'translateY(0)';
                  e.currentTarget.style.boxShadow = '0 10px 25px rgba(0,0,0,0.05)';
              }}
              >
                {/* Imagem */}
                <div style={{ width: '70px', height: '70px', backgroundColor: '#f0f0f0', borderRadius: '50%', marginRight: '20px', display: 'flex', alignItems: 'center', justifyContent: 'center', overflow: 'hidden' }}>
                    <img 
                        src={`/assets/img/lojas/${loja.imagem}`} 
                        alt={loja.nome} 
                        style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                        onError={(e) => { e.currentTarget.style.display = 'none'; e.currentTarget.nextElementSibling!.removeAttribute('hidden'); }}
                    />
                    <span hidden className="material-icons" style={{ color: '#ccc', fontSize: '30px' }}>store</span>
                </div>

                <div style={{ flex: 1 }}>
                    <h3 style={{ margin: '0 0 5px 0', fontSize: '18px', fontWeight: 'bold', color: '#333' }}>{loja.nome}</h3>
                    <div style={{ display: 'flex', alignItems: 'center' }}>
                        <span style={{ 
                            height: '10px', width: '10px', borderRadius: '50%', 
                            backgroundColor: loja.status === 'Aberto' ? '#28a745' : '#dc3545',
                            marginRight: '8px', display: 'inline-block'
                        }}></span>
                        <p style={{ margin: 0, fontSize: '14px', color: '#666', fontWeight: '500' }}>
                            {loja.status}
                        </p>
                    </div>
                </div>

                <span className="material-icons" style={{ color: '#dc3545' }}>chevron_right</span>
              </div>

            </div>
          ))}
        </div>

      </div>

      {/* Botão Voltar */}
      <div 
        onClick={() => router.back()} 
        style={{
            position: 'fixed', bottom: '30px', right: '30px', 
            backgroundColor: '#dc3545', color: 'white',
            width: '60px', height: '60px', borderRadius: '50%',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            cursor: 'pointer', zIndex: 999,
            boxShadow: '0 5px 15px rgba(220, 53, 69, 0.4)'
        }}
      >
        <span className="material-icons" style={{ fontSize: '30px' }}>arrow_back</span>
      </div>
    </main>
  );
}